-- Repair: several security scan tables were missing on instances where the baseline
-- mechanism marked earlier migrations as applied without executing them.
-- All statements use CREATE TABLE IF NOT EXISTS so this is safe to run multiple times.

-- 1. security_scan_tasks (base + all ALTER columns consolidated)
CREATE TABLE IF NOT EXISTS `security_scan_tasks` (
    `id`               BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
    `name`             VARCHAR(100)    NOT NULL                                                        COMMENT 'д»»еҠЎеҗҚз§°',
    `target_type`      VARCHAR(20)     NOT NULL                                                        COMMENT 'зӣ®ж Үзұ»еһӢ: cidr, ip_list',
    `target`           VARCHAR(500)    DEFAULT NULL                                                    COMMENT 'жү«жҸҸзӣ®ж Ү',
    `scan_type`        VARCHAR(20)     NOT NULL DEFAULT 'port'                                         COMMENT 'жү«жҸҸзұ»еһӢ: port, host-vuln, web',
    `status`           VARCHAR(20)     NOT NULL DEFAULT 'pending'                                      COMMENT 'д»»еҠЎзҠ¶жҖҒ: pending, running, paused, cancelled, completed, failed',
    `progress`         INT             NOT NULL DEFAULT 0                                              COMMENT 'иҝӣеәҰзҷҫеҲҶжҜ” 0-100',
    `total_ips`        INT             NOT NULL DEFAULT 0                                              COMMENT 'жҖ»IPж•°йҮҸ',
    `scanned_ips`      INT             NOT NULL DEFAULT 0                                              COMMENT 'е·Іжү«жҸҸIPж•°йҮҸ',
    `message`          VARCHAR(255)    DEFAULT NULL                                                    COMMENT 'еҪ“еүҚзҠ¶жҖҒдҝЎжҒҜ',
    `nuclei_version`   VARCHAR(50)     DEFAULT NULL                                                    COMMENT 'nucleiзүҲжң¬',
    `template_version` VARCHAR(50)     DEFAULT NULL                                                    COMMENT 'жЁЎжқҝзүҲжң¬',
    `high_risk`        INT             NOT NULL DEFAULT 0                                              COMMENT 'й«ҳеҚұжјҸжҙһж•°йҮҸ',
    `medium_risk`      INT             NOT NULL DEFAULT 0                                              COMMENT 'дёӯеҚұжјҸжҙһж•°йҮҸ',
    `low_risk`         INT             NOT NULL DEFAULT 0                                              COMMENT 'дҪҺеҚұжјҸжҙһж•°йҮҸ',
    `current_run_id`   BIGINT UNSIGNED DEFAULT NULL                                                    COMMENT 'еҪ“еүҚжү§иЎҢи®°еҪ•ID',
    `latest_run_id`    BIGINT UNSIGNED DEFAULT NULL                                                    COMMENT 'жңҖиҝ‘дёҖж¬Ўжү§иЎҢи®°еҪ•ID',
    `started_at`       DATETIME        DEFAULT NULL                                                    COMMENT 'ејҖе§Ӣж—¶й—ҙ',
    `completed_at`     DATETIME        DEFAULT NULL                                                    COMMENT 'е®ҢжҲҗж—¶й—ҙ',
    `created_by`       BIGINT UNSIGNED DEFAULT NULL                                                    COMMENT 'еҲӣе»әдәәID',
    `created_at`       DATETIME        NOT NULL DEFAULT CURRENT_TIMESTAMP                             COMMENT 'еҲӣе»әж—¶й—ҙ',
    `updated_at`       DATETIME        NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'жӣҙж–°ж—¶й—ҙ',
    INDEX `idx_status`          (`status`),
    INDEX `idx_created_at`      (`created_at`),
    INDEX `idx_current_run_id`  (`current_run_id`),
    INDEX `idx_latest_run_id`   (`latest_run_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='е®үе…Ёжү«жҸҸд»»еҠЎиЎЁ';

-- 2. security_scan_runs (base + phase-1 extension columns consolidated)
CREATE TABLE IF NOT EXISTS `security_scan_runs` (
    `id`               BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
    `task_id`          BIGINT UNSIGNED NOT NULL                                                        COMMENT 'жүҖеұһд»»еҠЎID',
    `task_name`        VARCHAR(100)    NOT NULL                                                        COMMENT 'д»»еҠЎеҗҚз§°еҝ«з…§',
    `target_type`      VARCHAR(20)     NOT NULL                                                        COMMENT 'зӣ®ж Үзұ»еһӢеҝ«з…§',
    `target`           VARCHAR(500)    NOT NULL                                                        COMMENT 'зӣ®ж Үеҝ«з…§',
    `scan_type`        VARCHAR(20)     NOT NULL                                                        COMMENT 'жү«жҸҸзұ»еһӢеҝ«з…§',
    `status`           VARCHAR(20)     DEFAULT 'pending'                                               COMMENT 'жү§иЎҢзҠ¶жҖҒ',
    `progress`         INT             DEFAULT 0                                                       COMMENT 'жү§иЎҢиҝӣеәҰ 0-100',
    `total_targets`    INT             DEFAULT 0                                                       COMMENT 'жҖ»зӣ®ж Үж•°',
    `scanned_targets`  INT             DEFAULT 0                                                       COMMENT 'е·Іжү«жҸҸзӣ®ж Үж•°',
    `message`          VARCHAR(255)    DEFAULT NULL                                                    COMMENT 'еҪ“еүҚзҠ¶жҖҒдҝЎжҒҜ',
    `high_risk`        INT             DEFAULT 0                                                       COMMENT 'й«ҳеҚұж•°йҮҸ',
    `medium_risk`      INT             DEFAULT 0                                                       COMMENT 'дёӯеҚұж•°йҮҸ',
    `low_risk`         INT             DEFAULT 0                                                       COMMENT 'дҪҺеҚұж•°йҮҸ',
    `run_no`           INT             DEFAULT NULL                                                    COMMENT 'еҗҢдёҖд»»еҠЎдёӢзҡ„иҝҗиЎҢеәҸеҸ·',
    `phase`            VARCHAR(30)     DEFAULT NULL                                                    COMMENT 'еҪ“еүҚйҳ¶ж®ө: prepare/discovery/verification/authenticated/reporting/completed',
    `config_snapshot`  JSON            DEFAULT NULL                                                    COMMENT 'жң¬ж¬Ўжү§иЎҢй…ҚзҪ®еҝ«з…§',
    `target_snapshot`  JSON            DEFAULT NULL                                                    COMMENT 'жң¬ж¬Ўеұ•ејҖзӣ®ж Үеҝ«з…§',
    `summary_snapshot` JSON            DEFAULT NULL                                                    COMMENT 'жң¬ж¬Ўз»ҹи®Ўж‘ҳиҰҒеҝ«з…§',
    `started_at`       DATETIME        DEFAULT NULL                                                    COMMENT 'ејҖе§Ӣж—¶й—ҙ',
    `completed_at`     DATETIME        DEFAULT NULL                                                    COMMENT 'е®ҢжҲҗж—¶й—ҙ',
    `cancelled_at`     DATETIME        DEFAULT NULL                                                    COMMENT 'еҸ–ж¶Ҳж—¶й—ҙ',
    `triggered_by`     BIGINT UNSIGNED DEFAULT NULL                                                    COMMENT 'и§ҰеҸ‘дәәID',
    `created_at`       DATETIME        DEFAULT CURRENT_TIMESTAMP                                       COMMENT 'еҲӣе»әж—¶й—ҙ',
    `updated_at`       DATETIME        DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP           COMMENT 'жӣҙж–°ж—¶й—ҙ',
    INDEX `idx_task_id`              (`task_id`),
    INDEX `idx_status`               (`status`),
    INDEX `idx_created_at`           (`created_at`),
    INDEX `idx_security_scan_runs_run_no`  (`task_id`, `run_no`),
    INDEX `idx_security_scan_runs_phase`   (`phase`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='е®үе…Ёжү«жҸҸжү§иЎҢи®°еҪ•иЎЁ';

-- 3. security_scan_targets (phase-1)
CREATE TABLE IF NOT EXISTS `security_scan_targets` (
    `id`                BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
    `run_id`            BIGINT UNSIGNED NOT NULL                                                       COMMENT 'жүҖеұһиҝҗиЎҢ ID',
    `task_id`           BIGINT UNSIGNED NOT NULL                                                       COMMENT 'жүҖеұһд»»еҠЎ ID',
    `parent_target_id`  BIGINT UNSIGNED DEFAULT NULL                                                   COMMENT 'зҲ¶зә§зӣ®ж Ү ID',
    `target_kind`       VARCHAR(20)     NOT NULL                                                       COMMENT 'зӣ®ж Үз§Қзұ»: ip/service/url/page/api/form/auth',
    `normalized_target` VARCHAR(500)    NOT NULL                                                       COMMENT 'ж ҮеҮҶеҢ–зӣ®ж Үж ҮиҜҶ',
    `host`              VARCHAR(255)    DEFAULT NULL                                                    COMMENT 'дё»жңә/IP/еҹҹеҗҚ',
    `port`              INT             DEFAULT NULL                                                    COMMENT 'з«ҜеҸЈ',
    `scheme`            VARCHAR(20)     DEFAULT NULL                                                    COMMENT 'еҚҸи®®: http/https/tcp/udp',
    `path`              VARCHAR(500)    DEFAULT NULL                                                    COMMENT 'URLи·Ҝеҫ„',
    `service_name`      VARCHAR(100)    DEFAULT NULL                                                    COMMENT 'жңҚеҠЎеҗҚз§°',
    `product_name`      VARCHAR(100)    DEFAULT NULL                                                    COMMENT 'дә§е“ҒеҗҚз§°',
    `version`           VARCHAR(100)    DEFAULT NULL                                                    COMMENT 'дә§е“ҒзүҲжң¬',
    `status`            VARCHAR(20)     DEFAULT 'pending'                                               COMMENT 'pending/running/completed/failed/skipped',
    `discovery_source`  VARCHAR(30)     DEFAULT NULL                                                    COMMENT 'зӣ®ж ҮжқҘжәҗ: nmap/http/browser/manual',
    `started_at`        DATETIME        DEFAULT NULL                                                    COMMENT 'ејҖе§Ӣж—¶й—ҙ',
    `completed_at`      DATETIME        DEFAULT NULL                                                    COMMENT 'е®ҢжҲҗж—¶й—ҙ',
    `metadata_json`     JSON            DEFAULT NULL                                                    COMMENT 'жү©еұ•е…ғж•°жҚ®',
    `created_at`        DATETIME        DEFAULT CURRENT_TIMESTAMP                                       COMMENT 'еҲӣе»әж—¶й—ҙ',
    `updated_at`        DATETIME        DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP           COMMENT 'жӣҙж–°ж—¶й—ҙ',
    INDEX `idx_scan_targets_run_id`      (`run_id`),
    INDEX `idx_scan_targets_task_id`     (`task_id`),
    INDEX `idx_scan_targets_parent_id`   (`parent_target_id`),
    INDEX `idx_scan_targets_kind_status` (`target_kind`, `status`),
    INDEX `idx_scan_targets_normalized`  (`normalized_target`(191))
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='жү«жҸҸиҝҗиЎҢзӣ®ж ҮеҚ•е…ғиЎЁ';

-- 4. security_scan_evidences (phase-1)
CREATE TABLE IF NOT EXISTS `security_scan_evidences` (
    `id`               BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
    `run_id`           BIGINT UNSIGNED NOT NULL                                                        COMMENT 'жүҖеұһиҝҗиЎҢ ID',
    `task_id`          BIGINT UNSIGNED NOT NULL                                                        COMMENT 'жүҖеұһд»»еҠЎ ID',
    `target_id`        BIGINT UNSIGNED DEFAULT NULL                                                    COMMENT 'е…іиҒ”зӣ®ж Ү ID',
    `evidence_type`    VARCHAR(30)     NOT NULL                                                        COMMENT 'иҜҒжҚ®зұ»еһӢ',
    `source_engine`    VARCHAR(30)     DEFAULT NULL                                                    COMMENT 'жқҘжәҗеј•ж“Һ: nmap/nuclei/browser/rule/auth',
    `digest`           CHAR(64)        DEFAULT NULL                                                    COMMENT 'иҜҒжҚ®ж‘ҳиҰҒпјҢз”ЁдәҺеҺ»йҮҚ',
    `request_excerpt`  MEDIUMTEXT      DEFAULT NULL                                                    COMMENT 'иҜ·жұӮзүҮж®ө',
    `response_excerpt` MEDIUMTEXT      DEFAULT NULL                                                    COMMENT 'е“Қеә”зүҮж®ө',
    `payload_excerpt`  MEDIUMTEXT      DEFAULT NULL                                                    COMMENT 'payloadзүҮж®ө',
    `metadata_json`    JSON            DEFAULT NULL                                                    COMMENT 'иҜҒжҚ®е…ғж•°жҚ®',
    `raw_json`         LONGTEXT        DEFAULT NULL                                                    COMMENT 'еҺҹе§Ӣз»“жһ„еҢ–з»“жһң',
    `storage_ref`      VARCHAR(500)    DEFAULT NULL                                                    COMMENT 'еӨ–йғЁеӯҳеӮЁеј•з”Ё',
    `created_at`       DATETIME        DEFAULT CURRENT_TIMESTAMP                                       COMMENT 'еҲӣе»әж—¶й—ҙ',
    `updated_at`       DATETIME        DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP           COMMENT 'жӣҙж–°ж—¶й—ҙ',
    INDEX `idx_scan_evidences_run_id`    (`run_id`),
    INDEX `idx_scan_evidences_task_id`   (`task_id`),
    INDEX `idx_scan_evidences_target_id` (`target_id`),
    INDEX `idx_scan_evidences_type`      (`evidence_type`),
    INDEX `idx_scan_evidences_digest`    (`digest`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='жү«жҸҸеҺҹе§ӢиҜҒжҚ®иЎЁ';

-- 5. security_scan_finding_occurrences (phase-1)
CREATE TABLE IF NOT EXISTS `security_scan_finding_occurrences` (
    `id`                     BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
    `run_id`                 BIGINT UNSIGNED NOT NULL                                                  COMMENT 'жүҖеұһиҝҗиЎҢ ID',
    `task_id`                BIGINT UNSIGNED NOT NULL                                                  COMMENT 'жүҖеұһд»»еҠЎ ID',
    `target_id`              BIGINT UNSIGNED DEFAULT NULL                                              COMMENT 'е…іиҒ”зӣ®ж Ү ID',
    `legacy_vulnerability_id` BIGINT UNSIGNED DEFAULT NULL                                             COMMENT 'е…је®№ security_vulnerabilities дё»й”®',
    `finding_key`            VARCHAR(255)    DEFAULT NULL                                              COMMENT 'и·ЁиҝҗиЎҢзЁіе®ҡиҜҶеҲ«й”®',
    `finding_family`         VARCHAR(20)     DEFAULT NULL                                              COMMENT 'з»“жһңе®¶ж—Ҹ: vulnerability/inventory',
    `finding_source`         VARCHAR(30)     DEFAULT NULL                                              COMMENT 'з»“жһңжқҘжәҗ',
    `severity`               VARCHAR(20)     DEFAULT NULL                                              COMMENT 'йЈҺйҷ©зӯүзә§',
    `confidence`             VARCHAR(20)     DEFAULT NULL                                              COMMENT 'зҪ®дҝЎеәҰ',
    `match_mode`             VARCHAR(30)     DEFAULT NULL                                              COMMENT 'еҢ№й…Қж–№ејҸ',
    `primary_cve_id`         VARCHAR(50)     DEFAULT NULL                                              COMMENT 'дё»CVE',
    `vuln_db_id`             BIGINT UNSIGNED DEFAULT NULL                                              COMMENT 'е…іиҒ”жјҸжҙһеә“дё»и®°еҪ•ID',
    `title`                  VARCHAR(200)    DEFAULT NULL                                              COMMENT 'ж Үйўҳеҝ«з…§',
    `status`                 VARCHAR(20)     DEFAULT 'open'                                            COMMENT 'еӨ„зҪ®зҠ¶жҖҒ',
    `verification_status`    VARCHAR(20)     DEFAULT 'pending'                                         COMMENT 'йӘҢиҜҒзҠ¶жҖҒ',
    `evidence_count`         INT             DEFAULT 0                                                 COMMENT 'е…іиҒ”иҜҒжҚ®ж•°',
    `first_seen_at`          DATETIME        DEFAULT NULL                                              COMMENT 'жң¬ж¬ЎиҝҗиЎҢйҰ–и§Ғж—¶й—ҙ',
    `last_seen_at`           DATETIME        DEFAULT NULL                                              COMMENT 'жң¬ж¬ЎиҝҗиЎҢжң«ж¬Ўе‘Ҫдёӯж—¶й—ҙ',
    `metadata_json`          JSON            DEFAULT NULL                                              COMMENT 'жү©еұ•е…ғж•°жҚ®',
    `created_at`             DATETIME        DEFAULT CURRENT_TIMESTAMP                                 COMMENT 'еҲӣе»әж—¶й—ҙ',
    `updated_at`             DATETIME        DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP     COMMENT 'жӣҙж–°ж—¶й—ҙ',
    INDEX `idx_scan_occurrences_run_id`          (`run_id`),
    INDEX `idx_scan_occurrences_task_id`         (`task_id`),
    INDEX `idx_scan_occurrences_target_id`       (`target_id`),
    INDEX `idx_scan_occurrences_legacy_vuln_id`  (`legacy_vulnerability_id`),
    INDEX `idx_scan_occurrences_source`          (`finding_source`),
    INDEX `idx_scan_occurrences_status`          (`status`),
    INDEX `idx_scan_occurrences_verification`    (`verification_status`),
    INDEX `idx_scan_occurrences_primary_cve`     (`primary_cve_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='жү«жҸҸеҸ‘зҺ°йЎ№-иҝҗиЎҢе…іиҒ”иЎЁ';
